let is_number s = let n = String.length s in let rec loop i seen_digit seen_dot seen_exp digit_after_exp = if i = n then seen_digit && digit_after_exp else let ch = s.[i] in if ch >= '0' && ch <= '9' then loop (i + 1) true seen_dot seen_exp (if seen_exp then true else digit_after_exp) else if ch = '+' || ch = '-' then if i <> 0 && s.[i - 1] <> 'e' && s.[i - 1] <> 'E' then false else loop (i + 1) seen_digit seen_dot seen_exp digit_after_exp else if ch = '.' then if seen_dot || seen_exp then false else loop (i + 1) seen_digit true seen_exp digit_after_exp else if ch = 'e' || ch = 'E' then if seen_exp || not seen_digit then false else loop (i + 1) seen_digit seen_dot true false else false in loop 0 false false false true
let () = let rec read_all acc = try read_all (read_line () :: acc) with End_of_file -> List.rev acc in match read_all [] with | [] -> () | t_str :: rest -> let t = int_of_string (String.trim t_str) in let rec take i xs = if i = 0 then [] else match xs with | x :: tl -> (if is_number x then "true" else "false") :: take (i - 1) tl | [] -> [] in print_string (String.concat "\n" (take t rest))
